script:
const { topic, questions } = workflow.params; const findings = await workflow.patterns.fanOutAndSynthesize({ items: questions, worker: (question) => workflow.agent(`Research this question about ${topic}: ${question}
Return concise findings, uncertainties, and source notes.`, { title: `Research: ${question}`, agentType: 'researcher' }), synthesizer: (results) => workflow.agent(`Synthesize these research findings for ${topic}. Highlight agreements, conflicts, and missing evidence.
${JSON.stringify(results.map((r) => r.text), null, 2)}`, { title: 'Research synthesis', agentType: 'researcher' }) }); const verified = await workflow.patterns.adversarialVerify({ result: findings.synthesis.text, verifier: (text) => workflow.agent(`Adversarially verify this research synthesis. List unsupported claims and source-quality risks.
${text}`, { title: 'Research verifier', agentType: 'verifier' }) }); workflow.artifact('deep-research-report', { topic, findings, verified }); return { topic, findings, verified };
